380	void WeaselTSF::_SelectCandidateOnCurrentPage(size_t index) {
381	  m_client.SelectCandidateOnCurrentPage(index);
382	  // simulate a VK_SELECT presskey to get data back and DoEditSession
383	  // the simulated keycode must be the one make TranslateKeycode Non-Zero return
384	  // fix me: are there any better ways?
385	  INPUT inputs[2];
386	  inputs[0].type = INPUT_KEYBOARD;
387	  inputs[0].ki = {VK_SELECT, 0, 0, 0, 0};
388	  inputs[1].type = INPUT_KEYBOARD;
389	  inputs[1].ki = {VK_SELECT, 0, KEYEVENTF_KEYUP, 0, 0};
390	  ::SendInput(sizeof(inputs) / sizeof(INPUT), inputs, sizeof(INPUT));
391	}
392	
393	void WeaselTSF::_HandleMousePageEvent(bool* const nextPage,
394	                                      bool* const scrollNextPage) {
395	  // from scrolling event
396	  if (scrollNextPage) {
397	    if (_cand->style().paging_on_scroll)
398	      m_client.ChangePage(!(*scrollNextPage));
399	    else {
400	      UINT current_select = 0, cand_count = 0;
401	      _cand->GetSelection(&current_select);
402	      _cand->GetCount(&cand_count);
403	      bool is_reposition = _cand->GetIsReposition();
404	      int offset = *scrollNextPage ? 1 : -1;
405	      offset = offset * (is_reposition ? -1 : 1);
406	      int index = (int)current_select + offset;
407	      if (index >= 0 && index < (int)cand_count)
408	        m_client.HighlightCandidateOnCurrentPage((size_t)index);
409	      else {
410	        KeyEvent ke{0, 0};
411	        ke.keycode = (index < 0) ? ibus::Up : ibus::Down;
412	        m_client.ProcessKeyEvent(ke);
413	      }
414	    }
415	  } else {  // from click event
416	    m_client.ChangePage(!(*nextPage));
417	  }
418	  _UpdateComposition(_pEditSessionContext);
419	}
420	
421	void WeaselTSF::_HandleMouseHoverEvent(const size_t index) {
422	  UINT current_select = 0;
423	  _cand->GetSelection(&current_select);
424	
425	  if (index != current_select) {
426	    m_client.HighlightCandidateOnCurrentPage(index);
427	    _UpdateComposition(_pEditSessionContext);
428	  }
429	}
430	
431	void WeaselTSF::HandleUICallback(size_t* const sel,
432	                                 size_t* const hov,
433	                                 bool* const next,
434	                                 bool* const scroll_next) {
435	  if (sel)
436	    _SelectCandidateOnCurrentPage(*sel);
437	  else if (hov)
438	    _HandleMouseHoverEvent(*hov);
439	  else if (next || scroll_next)
440	    _HandleMousePageEvent(next, scroll_next);
441	}
