295	void WeaselTSF::_HandleLangBarMenuSelect(UINT wID) {
296	  std::wstring dir{};
297	  switch (wID) {
298	    case ID_WEASELTRAY_RERUN_SERVICE:
299	    case ID_WEASELTRAY_INSTALLDIR:
300	      if (RegGetStringValue(HKEY_LOCAL_MACHINE, GetWeaselRegName(),
301	                            L"WeaselRoot", dir) == ERROR_SUCCESS) {
302	        if (wID == ID_WEASELTRAY_RERUN_SERVICE) {
303	          std::thread th([dir]() {
304	            ShellExecuteW(NULL, L"open", (dir + L"\\start_service.bat").c_str(),
305	                          NULL, dir.c_str(), SW_HIDE);
306	          });
307	          th.detach();
308	        } else
309	          open(dir);
310	      }
311	      break;
312	    case ID_WEASELTRAY_USERCONFIG:
313	      if (FAILED(RegGetStringValue(HKEY_CURRENT_USER, L"Software\\Rime\\Weasel",
314	                                   L"RimeUserDir", dir)) ||
315	          dir.empty()) {
316	        WCHAR _path[MAX_PATH] = {0};
317	        ExpandEnvironmentStringsW(L"%AppData%\\Rime", _path, _countof(_path));
318	        dir = std::wstring(_path);
319	      }
320	      if (!dir.empty() && fs::exists(dir))
321	        open(dir);
322	      else
323	        MessageBoxW(NULL, (L"Not found: " + dir).c_str(), L"RimeUserDir",
324	                    MB_ICONERROR | MB_OK);
325	      break;
326	    case ID_WEASELTRAY_LOGDIR:
327	      open(WeaselLogPath().wstring());
328	      break;
329	    case ID_WEASELTRAY_WIKI:
330	      open(L"https://rime.im/docs/");
331	      break;
332	    case ID_WEASELTRAY_FORUM:
333	      open(L"https://rime.im/discuss/");
334	      break;
335	    default:
336	      m_client.TrayCommand(wID);
337	      break;
338	  }
339	}
