341	HWND WeaselTSF::_GetFocusedContextWindow() {
342	  HWND hwnd = NULL;
343	  ITfDocumentMgr* pDocMgr;
344	  if (_pThreadMgr->GetFocus(&pDocMgr) == S_OK && pDocMgr != NULL) {
345	    ITfContext* pContext;
346	    if (pDocMgr->GetTop(&pContext) == S_OK && pContext != NULL) {
347	      ITfContextView* pContextView;
348	      if (pContext->GetActiveView(&pContextView) == S_OK &&
349	          pContextView != NULL) {
350	        pContextView->GetWnd(&hwnd);
351	        pContextView->Release();
352	      }
353	      pContext->Release();
354	    }
355	    pDocMgr->Release();
356	  }
357	
358	  if (hwnd == NULL) {
359	    HWND hwndForeground = GetForegroundWindow();
360	    if (GetWindowThreadProcessId(hwndForeground, NULL) == GetCurrentThreadId())
361	      hwnd = hwndForeground;
362	  }
363	
364	  return hwnd;
365	}
